import{_ as a,o as t,c as s,i as o}from"./chunks/framework.DP1yFSuu.js";const u=JSON.parse('{"title":"Installation & Setup FAQ","description":"Common questions about package installs, registries, framework support, and local testing.","frontmatter":{"title":"Installation & Setup FAQ","description":"Common questions about package installs, registries, framework support, and local testing."},"headers":[],"relativePath":"faqs/installation-and-setup.md","filePath":"faqs/installation-and-setup.md"}'),i={name:"faqs/installation-and-setup.md"};function n(l,e,r,p,d,c){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="installation-setup-faq" tabindex="-1">Installation &amp; Setup FAQ <a class="header-anchor" href="#installation-setup-faq" aria-label="Permalink to &quot;Installation &amp; Setup FAQ&quot;">​</a></h1><p>These questions cover the most common setup blockers for developers adopting Cobalt in an application or contributing inside the monorepo.</p><h2 id="which-cobalt-packages-do-i-install" tabindex="-1">Which Cobalt packages do I install? <a class="header-anchor" href="#which-cobalt-packages-do-i-install" aria-label="Permalink to &quot;Which Cobalt packages do I install?&quot;">​</a></h2><p>Most apps start with <code>@cobalt/tokens</code> plus exactly one component layer:</p><ul><li><code>@cobalt/components</code> if you want to use the web components directly</li><li><code>@cobalt/react</code> for React</li><li><code>@cobalt/vue</code> for Vue 3</li><li><code>@cobalt/angular</code> for Angular</li></ul><p>Typical installs look like this:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">npm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> install</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> @cobalt/tokens</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> @cobalt/components</span></span></code></pre></div><p>or:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">npm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> install</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> @cobalt/tokens</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> @cobalt/react</span></span></code></pre></div><p>See <a href="/cobalt-design-system/getting-started/developers.html">Getting Started for Developers</a> for the longer setup flow.</p><h2 id="do-i-need-private-registry-access" tabindex="-1">Do I need private registry access? <a class="header-anchor" href="#do-i-need-private-registry-access" aria-label="Permalink to &quot;Do I need private registry access?&quot;">​</a></h2><p>The short answer is no. Cobalt packages are published to a private npm repository but you would only need specific access if you are a contributor that has publish access. In order to consume Colbalt packages, you can set your registry to <code>https://registry.your-org.com</code> and install as normal.</p><ul><li>We recommend that you configure the registy URL at the project level using <code>.npmrc</code> rather than globally, to avoid conflicts with other projects that may use different registries.</li><li>For more information see the <a href="/cobalt-design-system/getting-started/developers.html#environment-setup">environment set up guide</a>.</li><li>If you encounter difficulties, <a href="/cobalt-design-system/resources/contact.html">contact</a> us.</li></ul><p>For local monorepo work, you do not need published packages at all.</p><h2 id="should-i-use-npm-or-pnpm" tabindex="-1">Should I use <code>npm</code> or <code>pnpm</code>? <a class="header-anchor" href="#should-i-use-npm-or-pnpm" aria-label="Permalink to &quot;Should I use `npm` or `pnpm`?&quot;">​</a></h2><p>Use whichever package manager matches your environment:</p><ul><li>Use <code>npm</code> or <code>pnpm</code> when consuming published Cobalt packages in an app.</li><li>Use <code>pnpm</code> when working inside the Cobalt monorepo, because the repo uses pnpm workspaces and the root scripts assume pnpm.</li></ul><p>Repo-level commands such as <code>pnpm build</code>, <code>pnpm dev</code>, and <code>pnpm test</code> should always be run with <code>pnpm</code>.</p><h2 id="can-i-use-cobalt-without-react-vue-or-angular" tabindex="-1">Can I use Cobalt without React, Vue, or Angular? <a class="header-anchor" href="#can-i-use-cobalt-without-react-vue-or-angular" aria-label="Permalink to &quot;Can I use Cobalt without React, Vue, or Angular?&quot;">​</a></h2><p>Yes. Cobalt’s primary implementation is a set of standard web components built with Lit.</p><p>If you do not need a framework wrapper, you can import per-component entry points such as:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FF9492;--shiki-light:#D73A49;">import</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> &#39;@cobalt/components/button&#39;</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">;</span></span></code></pre></div><p>and render:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">&lt;</span><span style="--shiki-dark:#72F088;--shiki-light:#22863A;">co-button</span><span style="--shiki-dark:#91CBFF;--shiki-light:#6F42C1;"> variant</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">=</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;">&quot;primary&quot;</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">&gt;Save&lt;/</span><span style="--shiki-dark:#72F088;--shiki-light:#22863A;">co-button</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">&gt;</span></span></code></pre></div><p>Framework wrappers exist for DX, typed props, and framework-native event handling, not because the components require a framework.</p><h2 id="what-node-and-framework-versions-are-supported" tabindex="-1">What Node and framework versions are supported? <a class="header-anchor" href="#what-node-and-framework-versions-are-supported" aria-label="Permalink to &quot;What Node and framework versions are supported?&quot;">​</a></h2><p>Current docs should be read this way:</p><ul><li>Repo support baseline: <code>Node 20+</code></li><li>Recommended contributor version: <code>Node 20.x</code></li><li><code>pnpm</code>: <code>9+</code></li></ul><p>Wrapper guidance currently documents:</p><ul><li>React: <code>18</code> and <code>19</code></li><li>Vue: <code>3.4+</code></li><li>Angular: <code>17+</code></li></ul><p>For the latest package-specific guidance, start with <a href="/cobalt-design-system/getting-started/developers.html">Getting Started for Developers</a> and the package READMEs.</p><h2 id="how-do-i-test-local-or-unpublished-cobalt-changes-in-another-app" tabindex="-1">How do I test local or unpublished Cobalt changes in another app? <a class="header-anchor" href="#how-do-i-test-local-or-unpublished-cobalt-changes-in-another-app" aria-label="Permalink to &quot;How do I test local or unpublished Cobalt changes in another app?&quot;">​</a></h2><p>The recommended path is <code>pnpm pack:local</code> from the monorepo root. It builds tarballs that match publish output, which is the safest way to catch packaging/export mistakes.</p><p>Use <code>pnpm link --global</code> only when you need faster iteration and you understand the tradeoff: linked packages can introduce duplicate dependency problems in host apps.</p><p>The contributor workflow is documented in <a href="/cobalt-design-system/contributing/development-setup.html">Development Setup</a>.</p><h2 id="do-i-always-need-to-import-fonts-and-base-styles" tabindex="-1">Do I always need to import fonts and base styles? <a class="header-anchor" href="#do-i-always-need-to-import-fonts-and-base-styles" aria-label="Permalink to &quot;Do I always need to import fonts and base styles?&quot;">​</a></h2><p>No. The import rules break down like this:</p><ul><li><code>@cobalt/tokens/css</code> is required</li><li><code>@cobalt/tokens/css/fonts</code> is recommended when you want Cobalt’s self-hosted font stack</li><li><code>@cobalt/tokens/css/base</code> is optional and adds the reset/base element styling layer</li></ul><p>If your components look unstyled, the first thing to verify is that <code>@cobalt/tokens/css</code> is loaded.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/cobalt-design-system/getting-started/developers.html">Getting Started for Developers</a></li><li><a href="/cobalt-design-system/contributing/development-setup.html">Development Setup</a></li><li><a href="/cobalt-design-system/tokens/">Token Reference</a></li></ul>',41)])])}const m=a(i,[["render",n]]);export{u as __pageData,m as default};
